    // --- Privacy panel modal (Phase 12B) ----------------------------------
    // These keys MAY CONTAIN HTML (rendered via innerHTML inside the prose
    // article). All anchor hrefs are static and trusted; we don't pass any
    // user-derived content into these strings, so the innerHTML use is safe.
    // The list-item bodies live in a single key each (privacyFetchesList,
    // privacyNotList, privacyExternalList) so a translator can render the
    // whole <li>…</li> block per locale without us splitting them apart.
    close:                    'Close',
    privacyTitle:             'Privacy',
    privacyLead:              'NoAdsTools processes images entirely in your browser. Image files never leave your device — there is no upload, no server-side rendering, and no cloud round-trip.',
    privacyFetchesHeading:    'What this site fetches (from this origin only)',
    privacyFetchesList:       '<li>HTML, CSS, JavaScript, and self-hosted Onest fonts.</li><li>The JSZip library (~97&nbsp;KB) — ONLY when you click "Export queue (ZIP)" for the first time. Vendored from <a href="https://stuk.github.io/jszip/" target="_blank" rel="noopener">stuk.github.io/jszip</a>, served from this origin. Used to package your batch exports into a single ZIP locally — no network traffic.</li><li>The jsPDF library (~420&nbsp;KB) — ONLY when you click PDF export for the first time. Vendored from <a href="https://github.com/parallax/jsPDF" target="_blank" rel="noopener">github.com/parallax/jsPDF</a> (npm), served from this origin. Used to build PDF files from your images locally — no network traffic.</li><li>The libheif HEIC/HEIF decoder (~1.1&nbsp;MB JavaScript + WebAssembly) — ONLY when you first import a <code>.heic</code> or <code>.heif</code> file. Vendored from <a href="https://github.com/catdad-experiments/libheif-js" target="_blank" rel="noopener">github.com/catdad-experiments/libheif-js</a> (which packages <a href="https://github.com/strukturag/libheif" target="_blank" rel="noopener">strukturag/libheif</a>), served from this origin. Cached by your browser thereafter.</li><li>Self-hosted ML model files for background removal (the <a href="https://github.com/imgly/background-removal-js" target="_blank" rel="noopener">@imgly/background-removal</a> ISNET fp16 model + <a href="https://github.com/microsoft/onnxruntime" target="_blank" rel="noopener">ONNX Runtime Web</a> WASM kernels — both the CPU SIMD path and the WebGPU/JSEP path so the model can run on the GPU when available). These files (~118&nbsp;MB total) are part of the site code, shipped from this repository — they are NOT a separate first-use download from a third party. Your browser fetches them only the first time you click "Remove background", from this origin, and caches them thereafter. The browser pulls only the kernels it actually needs — CPU-only browsers never download the WebGPU variant, and vice versa.</li><li>Self-hosted ML model file for face auto-detection (a <a href="https://github.com/google/mediapipe" target="_blank" rel="noopener">MediaPipe BlazeFace</a> ONNX export, re-distributed by <a href="https://huggingface.co/qualcomm/MediaPipe-Face-Detection" target="_blank" rel="noopener">Qualcomm AI Hub Models</a>, Apache-2.0). The graph (~78&nbsp;KB) + external weights (~517&nbsp;KB) are part of the site code, shipped from this repository. Your browser fetches them only the first time you click "Auto-detect faces" in the redact tool, from this origin, after a one-time consent prompt. Cached by your browser thereafter. Inference uses the same ONNX Runtime Web bundle already vendored for background removal — no additional runtime download.</li><li>Self-hosted OCR engine for text auto-detection (<a href="https://github.com/naptha/tesseract.js" target="_blank" rel="noopener">Tesseract.js v7</a> + <a href="https://github.com/naptha/tesseract.js-core" target="_blank" rel="noopener">tesseract.js-core v7</a>, both Apache-2.0, plus the English <code>eng.traineddata</code> LSTM model from <a href="https://github.com/tesseract-ocr/tessdata_fast" target="_blank" rel="noopener">tessdata_fast</a>, Apache-2.0). The library (~174&nbsp;KB JS + ~20&nbsp;MB of LSTM-only WebAssembly variants; your browser only downloads the single variant matching its SIMD support) plus the gzipped English model (~1.9&nbsp;MB) are part of the site code, shipped from this repository. Your browser fetches them only the first time you click "Detect text" in the redact tool, from this origin, after a one-time consent prompt. Cached by your browser thereafter. OCR runs entirely in your browser — recognized text never leaves your device.</li><li>The favicon and logo SVG.</li>',
    privacyNotHeading:        'What this site does NOT do',
    privacyNotList:           '<li>No third-party CDNs (no Google Fonts, no jsDelivr, no cdnjs, no Cloudflare-served libraries).</li><li>No analytics or telemetry (no Google Analytics, Plausible, Fathom, Mixpanel, gtag, fbq, or similar).</li><li>No cookies. No fingerprinting. No localStorage data shared off-device.</li><li>No upload of your images, masks, or edits. No "save to cloud" feature exists.</li>',
    privacyExternalHeading:   'External links that open on click',
    privacyExternalList:      '<li>GitHub source repository — only if you click the "Source" link in the footer.</li><li>Ko-fi tip page — only if you click "Tip" or "Support this site".</li><li>Nothing else; verify in DevTools &rarr; Network.</li>',
    privacyStorageHeading:    'Local storage',
    privacyStorageBody:       'Your preferences (language, theme, default export format and quality, overlay outline visibility, brush smoothing, thumbnail auto-refresh, and which topbar controls are visible) are saved in your browser\'s localStorage. You can clear them anytime via your browser\'s site-data tools. The keys we set are: <code>noadstools_lang</code>, <code>noadstools:settings:global</code>, <code>noadstools:settings:photo-editor</code>, <code>noadstools_bgremove_consent</code>, <code>noadstools_heic_consent</code>, <code>noadstools_face_detect_consent</code>, <code>noadstools_text_detect_consent_v1</code>, <code>noadstools_target_size</code>, <code>noadstools_upload_ready</code>, and <code>noadstools_watermark</code>. None of them contain image data.',
